const ids = String($env.GHL_LOCATION_IDS || '').split(',').map(s => s.trim()).filter(Boolean);
if (ids.length === 0) throw new Error('GHL_LOCATION_IDS no configurado');
return ids.map(location_id => ({ json: { location_id } }));

// Obtiene todos los pipelines y sus etapas desde GHL API v2.
// Endpoint: GET /opportunities/pipelines?locationId={id}
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const location_id = $input.first().json.location_id;
const apiKey = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

let allPipelines = [];
let retries = 0;

while (retries < 5) {
  try {
    const url = new URL('https://services.leadconnectorhq.com/opportunities/pipelines');
    url.searchParams.set('locationId', location_id);

    const resp = await fetch(url.toString(), {
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Version': '2021-07-28',
        'Content-Type': 'application/json'
      }
    });

    if (resp.status === 429) {
      await sleep(Math.pow(2, retries) * 1000);
      retries++;
      continue;
    }

    if (!resp.ok) throw new Error('GHL API error ' + resp.status + ' pipelines');

    const data = await resp.json();
    allPipelines = data.pipelines || [];
    break;
  } catch (err) {
    if (retries >= 4) throw err;
    await sleep(Math.pow(2, retries) * 1000);
    retries++;
  }
}

// Aplanar: una fila por (pipeline, stage)
const rows = [];
for (const pipeline of allPipelines) {
  const stages = pipeline.stages || [];
  stages.sort((a, b) => (a.position || 0) - (b.position || 0));
  for (let i = 0; i < stages.length; i++) {
    const stage = stages[i];
    const stageName = String(stage.name || '').trim();
    const nameLower = stageName.toLowerCase();
    rows.push({
      pipeline_id:   String(pipeline.id || '').trim(),
      pipeline_name: String(pipeline.name || '').trim().substring(0, 200),
      stage_id:      String(stage.id || '').trim(),
      stage_name:    stageName.substring(0, 200),
      stage_order:   stage.position ?? i,
      is_won_stage:  nameLower.includes('won') || nameLower.includes('ganado') || nameLower.includes('closed won'),
      is_lost_stage: nameLower.includes('lost') || nameLower.includes('perdido') || nameLower.includes('closed lost'),
      location_id,
      synced_at:     new Date().toISOString()
    });
  }
}

return [{ json: { location_id, rows } }];

// Upsert de todas las filas de pipeline en un batch usando la conexión Postgres de n8n.
// Usa INSERT ... ON CONFLICT DO UPDATE para mantener la dimensión actualizada.

const { location_id, rows } = $input.first().json;

if (!rows || rows.length === 0) {
  return [{ json: { location_id, upserted: 0 } }];
}

// Construir query upsert batch
const values = rows.map((r, i) => {
  const base = i * 9;
  return `($${base+1}, $${base+2}, $${base+3}, $${base+4}, $${base+5}, $${base+6}, $${base+7}, $${base+8}, $${base+9})`;
}).join(',\n');

const params = rows.flatMap(r => [
  r.pipeline_id, r.pipeline_name, r.stage_id, r.stage_name,
  r.stage_order, r.is_won_stage, r.is_lost_stage, r.location_id, r.synced_at
]);

const sql = `
INSERT INTO dim_pipelines
  (pipeline_id, pipeline_name, stage_id, stage_name, stage_order, is_won_stage, is_lost_stage, location_id, synced_at)
VALUES ${values}
ON CONFLICT (pipeline_id, stage_id, location_id)
DO UPDATE SET
  pipeline_name = EXCLUDED.pipeline_name,
  stage_name    = EXCLUDED.stage_name,
  stage_order   = EXCLUDED.stage_order,
  is_won_stage  = EXCLUDED.is_won_stage,
  is_lost_stage = EXCLUDED.is_lost_stage,
  synced_at     = EXCLUDED.synced_at
`;

return [{ json: { sql, params, location_id, count: rows.length } }];
